solution_code:
#include <iostream>

int main()
{
    constexpr int seconds_per_minute{ 60 };
    constexpr int minutes_per_hour{ 60 };
    constexpr int seconds_per_hour{ seconds_per_minute * minutes_per_hour };

    int total_seconds{};
    std::cin >> total_seconds;

    int hours{ total_seconds / seconds_per_hour };
    int remaining_seconds{ total_seconds % seconds_per_hour };

    std::cout << "hours: " << hours << "\n";
    std::cout << "remaining_seconds: " << remaining_seconds << "\n";

    return 0;
}

